function WatchlistManageModal({ lists, currentId, onClose, onSwitch, onCreate, onDelete, onRename }) {
  const [newName, setNewName] = useState("");
  const [renamingId, setRenamingId] = useState(null);

  const handleCreate = () => {
    if (!newName.trim()) return;
    onCreate(newName.trim());
    setNewName("");
  };

  const handleRename = (id, name) => {
    onRename(id, name);
    setRenamingId(null);
  };

  return (
    <div data-testid="watchlist-manage-modal" className="fixed inset-0 z-[200] flex items-start justify-center pt-20 bg-black/60 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-bg-base/95 border border-white/10 rounded-lg shadow-xl w-full max-w-md mx-4" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between px-4 py-3 border-b border-white/10">
          <h3 className="font-heading text-lg">Watchlists</h3>
          <button onClick={onClose} className="text-zinc-400 hover:text-white">
            <X className="w-5 h-5" />
          </button>
        </div>
        <div className="p-4">
          <div className="flex gap-2 mb-4">
            <input
              type="text"
              value={newName}
              onChange={e => setNewName(e.target.value)}
              placeholder="New watchlist name..."
              className="flex-1 bg-white/[0.04] border border-white/10 rounded px-3 py-2 text-sm font-mono outline-none"
              data-testid="watchlist-new-name"
            />
            <button
              onClick={handleCreate}
              disabled={!newName.trim()}
              className="px-4 py-2 bg-emerald-500/10 border border-emerald-500/40 text-emerald-300 rounded text-sm font-mono uppercase tracking-wider disabled:opacity-50"
              data-testid="watchlist-create-btn"
            >
              <Plus className="w-4 h-4" />
            </button>
          </div>
          <div className="space-y-1 max-h-64 overflow-y-auto custom-scrollbar pr-1">
            {lists.map((l) => (
              <div key={l.id} className="flex items-center gap-2">
                <button
                  onClick={() => onSwitch(l.id)}
                  className={`flex-1 text-left px-3 py-2 rounded text-sm font-mono transition-colors ${
                    l.id === currentId ? "bg-amber-500/20 text-amber-300" : "hover:bg-white/[0.06]"
                  }`}
                  data-testid={`watchlist-switch-${l.id}`}
                >
                  {renamingId === l.id ? (
                    <input
                      type="text"
                      defaultValue={l.name}
                      onBlur={e => handleRename(l.id, e.target.value)}
                      autoFocus
                      className="bg-transparent outline-none w-full"
                      data-testid={`watchlist-rename-input-${l.id}`}
                    />
                  ) : (
                    l.name
                  )}
                </button>
                <button
                  onClick={() => setRenamingId(l.id)}
                  className="p-2 text-zinc-400 hover:text-amber-300 rounded"
                  data-testid={`watchlist-rename-${l.id}`}
                >
                  <Edit3 className="w-3.5 h-3.5" />
                </button>
                <button
                  onClick={() => onDelete(l.id)}
                  disabled={lists.length <= 1 || l.id === currentId}
                  className="p-2 text-zinc-400 hover:text-red-400 rounded disabled:opacity-50"
                  data-testid={`watchlist-delete-${l.id}`}
                >
                  <Trash2 className="w-3.5 h-3.5" />
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function BlocklistModal({ blocklist, sellers, onClose }) {
  const [confirmClear, setConfirmClear] = useState(false);
  const [unblockTarget, setUnblockTarget] = useState(null);

  const sellerCounts = useMemo(() => {
    const map = new Map();
    for (const s of sellers || []) {
      map.set(s.name, s.totalListings || 0);
    }
    return map;
  }, [sellers]);

  const handleExport = async (sellerName) => {
    const seller = (sellers || []).find(s => s.name === sellerName);
    if (!seller) return;
    const blob = await renderSellerCardToBlob(seller);
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${sellerName.replace(/\s+/g, "-")}-trading-card.png`;
    a.click();
    setTimeout(() => URL.revokeObjectURL(url), 1000);
  };

  return (
    <div data-testid="blocklist-modal" className="fixed inset-0 z-[200] flex items-start justify-center pt-20 bg-black/60 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-bg-base/95 border border-white/10 rounded-lg shadow-xl w-full max-w-md mx-4" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between px-4 py-3 border-b border-white/10">
          <h3 className="font-heading text-lg">Blocked Sellers</h3>
          <button onClick={onClose} className="text-zinc-400 hover:text-white">
            <X className="w-5 h-5" />
          </button>
        </div>
        <div className="p-4">
          {blocklist.sellers.length === 0 ? (
            <div className="text-zinc-400 text-center py-8">No blocked sellers.</div>
          ) : (
            <>
              <div className="space-y-2 max-h-64 overflow-y-auto custom-scrollbar pr-1 mb-4">
                {blocklist.sellers.map((seller) => (
                  <div key={seller} className="flex items-center gap-2">
                    <span className="flex-1 text-sm font-mono">{seller}</span>
                    <span className="text-zinc-500 font-mono text-xs">
                      {sellerCounts.get(seller) ? `${sellerCounts.get(seller)} listings` : "—"}
                    </span>
                    <button
                      onClick={() => handleExport(seller)}
                      className="p-1.5 text-zinc-400 hover:text-emerald-300 rounded"
                      data-testid={`export-${seller}`}
                      title="Export trading card"
                    >
                      <Download className="w-3.5 h-3.5" />
                    </button>
                    <button
                      onClick={() => setUnblockTarget(seller)}
                      className="px-3 py-1.5 text-xs text-red-400 border border-red-400/40 hover:border-red-400 hover:bg-red-400/10 rounded transition-colors"
                      data-testid={`unblock-${seller}`}
                    >
                      Unblock
                    </button>
                  </div>
                ))}
              </div>
              <button
                onClick={() => setConfirmClear(true)}
                className="w-full py-2 text-xs text-red-400 border border-red-400/40 hover:bg-red-400/10 rounded"
                data-testid="clear-all-blocked"
              >
                Clear All Blocked
              </button>
            </>
          )}
        </div>
      </div>

      {/* Unblock confirmation */}
      <AlertDialog open={unblockTarget !== null} onOpenChange={(o) => { if (!o) setUnblockTarget(null); }}>
        <AlertDialogPortal>
          <AlertDialogOverlay />
          <AlertDialogContent className="bg-bg-base border-white/10 text-white">
            <AlertDialogHeader>
              <AlertDialogTitle>Unblock {unblockTarget}?</AlertDialogTitle>
              <AlertDialogDescription className="text-zinc-400">
                Listings from this seller will no longer be hidden.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel className="border-white/10 text-zinc-300 hover:bg-white/5">Cancel</AlertDialogCancel>
              <AlertDialogAction className="bg-red-500 hover:bg-red-600 text-white" onClick={() => { blocklist.toggle(unblockTarget); setUnblockTarget(null); }}>
                Unblock
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialogPortal>
      </AlertDialog>

      {/* Clear all confirmation */}
      <AlertDialog open={confirmClear} onOpenChange={(o) => { if (!o) setConfirmClear(false); }}>
        <AlertDialogPortal>
          <AlertDialogOverlay />
          <AlertDialogContent className="bg-bg-base border-white/10 text-white">
            <AlertDialogHeader>
              <AlertDialogTitle>Clear all blocked sellers?</AlertDialogTitle>
              <AlertDialogDescription className="text-zinc-400">
                This will unblock all {blocklist.count} sellers. This cannot be undone.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel className="border-white/10 text-zinc-300 hover:bg-white/5">Cancel</AlertDialogCancel>
              <AlertDialogAction className="bg-red-500 hover:bg-red-600 text-white" onClick={() => { blocklist.clear(); setConfirmClear(false); onClose(); }}>
                Clear all
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialogPortal>
      </AlertDialog>
    </div>
  );
}
