const SANS = "Unbounded, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif";
const MONO = "Geist Mono, ui-monospace, SFMono-Regular, Menlo, Consolas, monospace";

/**
 * Shared theme configuration for consistent branding across canvas renders.
 */
function themeColors() {
  const isDark = document.documentElement.classList.contains("dark");
  return {
    isDark,
    bg: isDark ? "#09090b" : "#f5f5f0",
    surface: isDark ? "#18181b" : "#e8e8e3",
    text: isDark ? "#fafafa" : "#18181b",
    muted: isDark ? "#a1a1aa" : "#52525b",
    subtle: isDark ? "#52525b" : "#71717a",
    accent: isDark ? "#fbbf24" : "#d97706", // Amber for Sellers
    accentSoft: isDark ? "#451a03" : "#fef3c7",
    emerald: isDark ? "#10b981" : "#059669",
    red: isDark ? "#ef4444" : "#dc2626",
    border: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.12)",
    grid: isDark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.04)",
    glowPrimary: isDark ? "rgba(251,191,36,0.12)" : "rgba(251,191,36,0.1)",
  };
}

/**
 * Helper to draw rounded rectangles on the canvas.
 */
function fillRoundRect(ctx, x, y, w, h, r, fill, stroke = null) {
  const radius = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
  ctx.fillStyle = fill;
  ctx.fill();
  if (stroke) {
    ctx.strokeStyle = stroke;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

/**
 * Renders a Twitter-style verified badge.
 */
function drawVerifiedBadge(ctx, x, y, size, t) {
  ctx.save();
  const color = t.accent;
  
  // Starburst shape for the badge background
  ctx.beginPath();
  const points = 8;
  const innerRadius = size * 0.4;
  const outerRadius = size * 0.5;
  const cx = x + size / 2;
  const cy = y + size / 2;
  
  for (let i = 0; i < points * 2; i++) {
    const r = i % 2 === 0 ? outerRadius : innerRadius;
    const angle = (Math.PI / points) * i;
    const px = cx + Math.cos(angle) * r;
    const py = cy + Math.sin(angle) * r;
    if (i === 0) ctx.moveTo(px, py);
    else ctx.lineTo(px, py);
  }
  ctx.closePath();
  ctx.fillStyle = color;
  ctx.fill();

  // Checkmark
  ctx.beginPath();
  ctx.strokeStyle = t.bg;
  ctx.lineWidth = size * 0.12;
  ctx.lineCap = "round";
  ctx.lineJoin = "round";
  ctx.moveTo(cx - size * 0.18, cy);
  ctx.lineTo(cx - size * 0.04, cy + size * 0.14);
  ctx.lineTo(cx + size * 0.2, cy - size * 0.12);
  ctx.stroke();
  
  ctx.restore();
}

/**
 * Multi-line text renderer with automatic wrapping and overflow handling.
 */
function drawTextLines(ctx, text, x, y, maxWidth, lineHeight, maxLines) {
  const words = String(text || "").split(/\s+/).filter(Boolean);
  const lines = [];
  let line = "";
  
  for (const word of words) {
    const next = line ? `${line} ${word}` : word;
    if (ctx.measureText(next).width <= maxWidth || !line) {
      line = next;
    } else {
      lines.push(line);
      line = word;
    }
    if (lines.length >= maxLines) break;
  }
  
  if (line && lines.length < maxLines) lines.push(line);
  
  // Truncate last line if needed
  if (lines.length === maxLines) {
    let last = lines[lines.length - 1];
    if (ctx.measureText(`${last}...`).width > maxWidth) {
      while (ctx.measureText(`${last}...`).width > maxWidth && last.length > 1) {
        last = last.slice(0, -1);
      }
      lines[lines.length - 1] = `${last}...`;
    }
  }

  lines.forEach((val, i) => ctx.fillText(val, x, y + i * lineHeight));
  return lines.length * lineHeight;
}

/**
 * Loads an image from a URL and returns a Promise.
 */
function loadImage(url) {
  return new Promise((resolve) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => resolve(img);
    img.onerror = () => resolve(null);
    img.src = url;
  });
}

/**
 * Main composition for the seller trading card.
 */
async function composeSellerCard(ctx, seller, width, height, t) {
  // Background Grid & Glow
  ctx.fillStyle = t.bg;
  ctx.fillRect(0, 0, width, height);
  
  const gradient = ctx.createRadialGradient(width * 0.8, height * 0.2, 0, width * 0.8, height * 0.2, 600);
  gradient.addColorStop(0, t.glowPrimary);
  gradient.addColorStop(1, "transparent");
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, width, height);

  ctx.strokeStyle = t.grid;
  ctx.lineWidth = 1;
  const gridSize = 40;
  for (let x = 0; x <= width; x += gridSize) {
    ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, height); ctx.stroke();
  }
  for (let y = 0; y <= height; y += gridSize) {
    ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(width, y); ctx.stroke();
  }

  // Header
  ctx.font = `900 12px ${MONO}`;
  ctx.fillStyle = t.accent;
  ctx.beginPath(); ctx.arc(62, 46, 4, 0, Math.PI * 2); ctx.fill();
  ctx.fillText("CMI SELLER PROFILE", 74, 50);
  
  ctx.fillStyle = t.subtle;
  ctx.textAlign = "right";
  ctx.font = `700 11px ${MONO}`;
  ctx.fillText(new Date().toISOString().replace("T", " ").split(".")[0] + " UTC", width - 56, 50);
  ctx.textAlign = "left";

  // Profile Section
  const avatarUrl = `https://render.crafty.gg/3d/bust/${encodeURIComponent(seller.name)}`;
  const avatar = await loadImage(avatarUrl);
  const avatarSize = 180;
  const avatarX = 64;
  const avatarY = 120;
  
  fillRoundRect(ctx, avatarX, avatarY, avatarSize, avatarSize, 24, t.surface, t.border);
  if (avatar) {
    ctx.drawImage(avatar, avatarX + 10, avatarY + 10, avatarSize - 20, avatarSize - 20);
  } else {
    ctx.font = `900 48px ${SANS}`;
    ctx.fillStyle = t.subtle;
    ctx.textAlign = "center";
    ctx.fillText(seller.name.slice(0, 2).toUpperCase(), avatarX + avatarSize / 2, avatarY + avatarSize / 2 + 18);
    ctx.textAlign = "left";
  }

  // Seller Name & Verified Badge
  const nameX = avatarX + avatarSize + 40;
  const nameY = avatarY + 60;
  ctx.font = `900 72px ${SANS}`;
  ctx.fillStyle = t.text;
  ctx.letterSpacing = "-0.02em";
  const nameWidth = ctx.measureText(seller.name).width;
  const maxNameWidth = width - nameX - 100;
  
  if (nameWidth > maxNameWidth) {
    ctx.font = `900 56px ${SANS}`; // Scale down for long names
  }
  ctx.fillText(seller.name, nameX, nameY);
  ctx.letterSpacing = "normal";

  if (seller.accuracyLabel === "Trustworthy" || seller.isVerified) {
    const badgeX = nameX + Math.min(nameWidth, maxNameWidth) + 15;
    drawVerifiedBadge(ctx, badgeX, nameY - 55, 48, t);
  }

  // Identity / Platform
  ctx.font = `700 16px ${MONO}`;
  ctx.fillStyle = t.subtle;
  const isBedrock = seller.identityKey?.startsWith("bedrock");
  const platform = isBedrock ? "BEDROCK EDITION" : seller.uuid ? `JAVA · ${seller.uuid.slice(0, 8).toUpperCase()}` : "PLATFORM UNKNOWN";
  ctx.fillText(platform, nameX, nameY + 40);

  // Reputation Chip
  const label = seller.isBlacklisted ? "FLAGGED" : (seller.accuracyLabel || "NEUTRAL").toUpperCase();
  const labelColor = label === "FLAGGED" ? t.red : label === "SUSPICIOUS" ? t.accent : label === "TRUSTWORTHY" ? t.emerald : t.muted;
  
  ctx.font = `800 14px ${MONO}`;
  const labelW = ctx.measureText(label).width + 24;
  fillRoundRect(ctx, nameX, nameY + 65, labelW, 32, 6, labelColor + "1A", labelColor + "33");
  ctx.fillStyle = labelColor;
  ctx.fillText(label, nameX + 12, nameY + 86);

  // Stats Grid
  const statsY = 400;
  const statsH = 220;
  const cardW = (width - 128 - 48) / 3;
  
  const drawStatCard = (x, title, value, sub, color) => {
    fillRoundRect(ctx, x, statsY, cardW, statsH, 20, t.surface, t.border);
    ctx.font = `800 12px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText(title.toUpperCase(), x + 24, statsY + 40);
    
    ctx.font = `900 48px ${SANS}`;
    ctx.fillStyle = color || t.text;
    ctx.fillText(value, x + 24, statsY + 110);
    
    ctx.font = `700 14px ${MONO}`;
    ctx.fillStyle = t.subtle;
    ctx.fillText(sub.toUpperCase(), x + 24, statsY + 150);
  };

  const markup = seller.avgMarkupPercent || 0;
  const markupColor = markup > 15 ? t.red : markup < -5 ? t.emerald : t.text;

  drawStatCard(64, "Inventory", String(seller.totalListings || 0), "Total active listings", t.text);
  drawStatCard(64 + cardW + 24, "Market Bias", `${markup > 0 ? "+" : ""}${markup.toFixed(1)}%`, "Avg markup vs median", markupColor);
  drawStatCard(64 + (cardW + 24) * 2, "Accuracy", `${(100 - (seller.overpricedRatio || 0)).toFixed(1)}%`, "Fair pricing score", t.text);

  // Top Listing Designation (P3-2: Premium Status)
  const isTopListing = seller.totalListings > 50 || (seller.accuracyLabel === "Trustworthy" && markup < 5);
  if (isTopListing) {
    const badgeW = 160;
    const badgeH = 32;
    const badgeX = width - 64 - badgeW;
    const badgeY = statsY - 48;
    fillRoundRect(ctx, badgeX, badgeY, badgeW, badgeH, 6, t.emerald + "22", t.emerald + "44");
    ctx.font = `900 11px ${MONO}`;
    ctx.fillStyle = t.emerald;
    ctx.textAlign = "center";
    ctx.fillText("TOP LISTING STATUS", badgeX + badgeW / 2, badgeY + 20);
    ctx.textAlign = "left";
  }

  // Bottom Content / Info
  const footerY = statsY + statsH + 50; // Reduced spacing from stats cards
  ctx.font = `600 22px ${SANS}`; // Removed italic, adjusted size
  ctx.fillStyle = t.muted;
  const bio = seller.isBlacklisted ? "This seller has been flagged for multiple violations." : "Active participant in the Castia economy with recorded trade history.";
  drawTextLines(ctx, bio, 64, footerY, width - 128, 30, 2);

  // Footer
  ctx.save();
  ctx.font = `800 10px ${MONO}`;
  ctx.fillStyle = t.subtle;
  ctx.fillText("CASTIA MARKET INSIGHT · SELLER TRADING CARD", 64, height - 32);
  ctx.textAlign = "right";
  ctx.fillText("VERIFIED ON-CHAIN DATA", width - 64, height - 32);
  ctx.restore();
}

/**
 * Public API to render the seller card and return it as a Blob.
 */
export async function renderSellerCardToBlob(seller) {
  const width = 1080;
  const height = 1080; // Square compact format
  
  return new Promise((resolve, reject) => {
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext("2d");
    if (!ctx) { reject(new Error("Canvas context failed")); return; }

    const t = themeColors();
    
    // Performance optimization: Render in a single pass
    composeSellerCard(ctx, seller, width, height, t).then(() => {
      canvas.toBlob((blob) => {
        if (blob) resolve(blob);
        else reject(new Error("Blob conversion failed"));
      }, "image/png");
    }).catch(reject);
  });
}
